/**
 * SoundManager - Singleton utility for handling app-wide sound effects
 * Optimized with Base64 Tap for 100% reliability and Audio Unlock
 */
const SoundManager = {
  muted: false,
  volume: 0.4,
  unlocked: false,
  sounds: {
    // Tap sound embedded as base64 for zero-latency, zero-network-fail feedback
    tap: new Audio('data:audio/mp3;base64,'),
    success: new Audio('https://www.soundjay.com/misc/sounds/bell-ringing-05.mp3'),
    timer_end: new Audio('https://www.soundjay.com/clock/sounds/alarm-clock-elapsed-01.mp3'),
    transition: new Audio('https://www.soundjay.com/buttons/sounds/button-28.mp3'),
  },

  init() {
    this.muted = localStorage.getItem('app_muted') === 'true';
    Object.values(this.sounds).forEach(audio => {
      audio.volume = this.volume;
      audio.preload = 'auto';
    });

    const unlock = () => {
      if (this.unlocked) return;
      Object.values(this.sounds).forEach(audio => {
        const p = audio.play();
        if (p) p.then(() => { audio.pause(); audio.currentTime = 0; }).catch(() => {});
      });
      this.unlocked = true;
      document.removeEventListener('click', unlock);
      document.removeEventListener('touchstart', unlock);
    };
    document.addEventListener('click', unlock);
    document.addEventListener('touchstart', unlock);
    this.updateIconFeedback();
  },

  play(soundName) {
    if (this.muted || !this.sounds[soundName]) return;
    try {
      const audio = this.sounds[soundName];
      audio.currentTime = 0;
      audio.play().catch(() => {});
    } catch (e) {}
  },

  toggleMute() {
    this.muted = !this.muted;
    localStorage.setItem('app_muted', this.muted);
    this.updateIconFeedback();
    return this.muted;
  },

  updateIconFeedback() {
    const soundBtns = document.querySelectorAll('.pomo-sound-btn, #pomo-sound-btn');
    soundBtns.forEach(btn => {
      const icon = btn.querySelector('.material-symbols-outlined');
      if (icon) {
        icon.textContent = this.muted ? 'volume_off' : 'volume_up';
        icon.style.color = this.muted ? '#64748b' : '#7c3aed';
      }
    });
  }
};
window.SoundManager = SoundManager;
